  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })

  const formData = await request.formData()
  const file = formData.get('file') as File | null
  if (!file) return NextResponse.json({ error: 'No file provided' }, { status: 400 })

  const ext = file.name.split('.').pop()?.toLowerCase() ?? ''
  if (!['csv', 'xls', 'xlsx', 'pdf'].includes(ext)) {
    return NextResponse.json({ error: `Unsupported file type ".${ext}"` }, { status: 400 })
  }

  const buffer = Buffer.from(await file.arrayBuffer())
  let rows
  if (ext === 'csv') rows = parseCsvBank(buffer.toString('utf-8'))
  else if (ext === 'xls' || ext === 'xlsx') rows = parseXlsBank(buffer)
  /** PDF: text extraction via pdf-parse, then regex — not OCR */
  else rows = await parsePdfBank(buffer)

  if (rows.length === 0) {
    return NextResponse.json({ error: 'No transactions parsed' }, { status: 422 })
  }

  const orgId = await getCurrentOrgId()
  const rules = await fetchRules(orgId)
  const batchId = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`
  let inserted = 0, skipped = 0

  for (const txn of rows) {
    const exists = await supabase.from('bank_transactions').select('id')
      .eq('org_id', orgId).eq('transaction_date', txn.transaction_date)
      .eq('description', txn.description)
      .eq('debit', txn.debit ?? 0).eq('credit', txn.credit ?? 0).limit(1)
    if (exists.data?.length) { skipped++; continue }

    const { category, source } = categorize(txn.description, rules)
